features.snippet:
always @(sig1 or sig2) begin
  result = sig1 & sig2;
end

logic [31:0] data_sig;
always @(posedge data_sig or negedge data_sig) begin
  seq_result <= data_sig;
end

always @* begin
  last_combo_seqnum = func_combo(handle, combo_val);
end
always @(posedge sig or negedge sig) begin
  last_seq_seqnum <= func_seq(handle, sig, tmp);
  result_seq <= tmp;
end
always @* begin
  result = (last_seq_seqnum > last_combo_seqnum) ? result_seq : combo_val;
end

wire [31:0] combo_result;
wire [31:0] seq_result;
wire [31:0] final = (seq_seqnum > combo_seqnum) ? seq_result : combo_result;
